%%%%%%%%%% Function f3wayPltV01.m %%%%%%%%%%% Function 3 way plot, ver.1% Kei Nakamura% Created on Monday, May 21st 2007.% Modified on %% function ok = f3wayPltV01(hndl,x1,x2,x3,ttl,lbl)% plot 3 figures for 3 parameters,% like a-b, b-c, c-a% hndl: three hundles for figures% x1-x3: plot elements% ttl: 3 titles for plot% lbl: 3 labels for x1-x3function pHndl = f3wayPltV01(hndl,x1,x2,x3,ttl,lbl)  %function headersubplot(hndl(1));pHndl(1) = plot(x2,x1,'bo');title(ttl{1});xlabel(lbl{2});ylabel(lbl{1});a = axis;axis([0 a(2) 0 a(4)]);subplot(hndl(2));pHndl(2) = plot(x3,x2,'ro');title(ttl{2});xlabel(lbl{3});ylabel(lbl{2});a = axis;axis([0 a(2) 0 a(4)]);subplot(hndl(3));pHndl(3) = plot(x1,x3,'go');title(ttl{3});xlabel(lbl{1});ylabel(lbl{3});a = axis;axis([0 a(2) 0 a(4)]);
